pub unsafe fn from_vec_with_nul_unchecked(v: Vec<u8>) -> Self {
    debug_assert!(memchr::memchr(0, &v).unwrap() + 1 == v.len());
    unsafe { Self::_from_vec_with_nul_unchecked(v) }
}

